export const getCheckoutSuccessUrl = (params: CheckoutSuccessParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : value.toString())
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/checkout/success?${stringifiedParams}` : `/api/checkout/success`
}

/**
 * @summary Handle post-checkout success; mark listing as sold
 */
